  ('raciocinio_logico', 'Combinatoria - Topico 0296', 'Topico expandido automaticamente para Raciocinio Logico, area Combinatoria, modulo 11.', 'Combinatoria', 'Modulo 11', 'topic', 'intermediario', 70, 3, 0.12, 0.87, 'raciocinio_logico_combinatoria_0296'),
  ('raciocinio_logico', 'Probabilidade - Topico 0297', 'Topico expandido automaticamente para Raciocinio Logico, area Probabilidade, modulo 11.', 'Probabilidade', 'Modulo 11', 'topic', 'avancado', 80, 4, 0.1, 0.86, 'raciocinio_logico_probabilidade_0297'),
  ('raciocinio_logico', 'Proposicoes - Topico 0298', 'Topico expandido automaticamente para Raciocinio Logico, area Proposicoes, modulo 11.', 'Proposicoes', 'Modulo 11', 'subtopic', 'avancado', 30, 5, 0.07, 0.84, 'raciocinio_logico_proposicoes_0298'),
  ('raciocinio_logico', 'Conectivos - Topico 0299', 'Topico expandido automaticamente para Raciocinio Logico, area Conectivos, modulo 11.', 'Conectivos', 'Modulo 11', 'topic', 'iniciante', 40, 1, 0.05, 0.82, 'raciocinio_logico_conectivos_0299'),
  ('raciocinio_logico', 'Equivalencias - Topico 0300', 'Topico expandido automaticamente para Raciocinio Logico, area Equivalencias, modulo 11.', 'Equivalencias', 'Modulo 11', 'topic', 'intermediario', 50, 2, 0.05, 0.81, 'raciocinio_logico_equivalencias_0300')
), topic_map as (
  select
    lower(regexp_replace(d.nome, '[^a-zA-Z0-9]+', '_', 'g')) as disciplina_slug,
    t.nome as topic_name,
    t.id as topico_id
  from public.topicos t
  join public.disciplinas d on d.id = t.disciplina_id
)
insert into public.topico_dna (
  topico_id,
  codigo,
  dificuldade,
  frequencia_enem,
  frequencia_concursos,
  tempo_medio_aprendizado_min,
  relevancia_global
)
select
  tm.topico_id,
  ts.codigo,
  ts.dificuldade,
  ts.frequencia_enem * 100,
  ts.frequencia_concursos * 100,
  ts.tempo_estimado_min,
  round(((ts.frequencia_enem + ts.frequencia_concursos) / 2.0) * 100)
from topic_seed ts
join topic_map tm
  on tm.disciplina_slug = ts.disciplina_slug
 and tm.topic_name = ts.topic_name
on conflict (topico_id) do update
set codigo = excluded.codigo,
    dificuldade = excluded.dificuldade,
    frequencia_enem = excluded.frequencia_enem,
    frequencia_concursos = excluded.frequencia_concursos,
    tempo_medio_aprendizado_min = excluded.tempo_medio_aprendizado_min,
    relevancia_global = excluded.relevancia_global;

